const items = $input.all();

const rows = items.map((item) => item.json);

const totalMessages = rows.length;
const sessions = new Set(rows.map(r => r.session_id).filter(Boolean));

const humanMessages = rows.filter(r =>
  String(r.role || "").toLowerCase().includes("human")
);

const aiMessages = rows.filter(r =>
  String(r.role || "").toLowerCase().includes("ai")
);

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

const tableRows = rows.map(row => `
  <tr>
    <td>${escapeHtml(row.id)}</td>
    <td>${escapeHtml(row.session_id)}</td>
    <td>${escapeHtml(row.role)}</td>
    <td>${escapeHtml(row.content).slice(0, 1000)}</td>
  </tr>
`).join("");

const html = `
<h2>Rapport OceanSentinel — Historique du chatbot</h2>

<h3>Résumé</h3>
<ul>
  <li>Total messages : ${totalMessages}</li>
  <li>Sessions distinctes : ${sessions.size}</li>
  <li>Messages utilisateur : ${humanMessages.length}</li>
  <li>Messages assistant : ${aiMessages.length}</li>
</ul>

<h3>Derniers messages</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;width:100%;">
  <thead>
    <tr>
      <th>ID</th>
      <th>Session</th>
      <th>Rôle</th>
      <th>Contenu</th>
    </tr>
  </thead>
  <tbody>
    ${tableRows || "<tr><td colspan='4'>Aucun message trouvé.</td></tr>"}
  </tbody>
</table>

<p><strong>Décision :</strong> GO — rapport généré depuis PostgreSQL.</p>
`;

return [
  {
    json: {
      status: "GO",
      report_type: "chat_history_html",
      total_messages: totalMessages,
      total_sessions: sessions.size,
      human_messages: humanMessages.length,
      ai_messages: aiMessages.length,
      html_report: html,
      decision: "GO — HTML chat history report generated."
    }
  }
];

