parameters.jsCode:
const input = $json;

function extractText(value) {
  if (!value) return "";

  if (typeof value === "string") {
    return value;
  }

  if (Array.isArray(value)) {
    return value.map(extractText).filter(Boolean).join("\n\n");
  }

  if (typeof value === "object") {
    return (
      value.output ||
      value.text ||
      value.response ||
      value.answer ||
      value.message ||
      value.content ||
      value.data?.output ||
      value.data?.text ||
      value.data?.response ||
      value.data?.answer ||
      ""
    );
  }

  return "";
}

const finalText =
  extractText(input).trim() ||
  "Je ne dispose pas d’éléments suffisants dans la base OceanSentinel pour l’affirmer.";

return {
  json: {
    output: finalText,
    text: finalText
  }
};

